            setBatchScaleX(''); setBatchScaleY(''); setBatchSizeW(''); setBatchSizeH('')
            setBatchColor(''); setBatchRot(''); setBatchLayer(''); setBatchNamePrefix(''); setBatchNameSuffix('')
              setBatchRegexPat(''); setBatchRegexRepl(''); setBatchRegexErr(false)
